### Handle Events on 3D Objects in React Three Fiber

Source: https://context7.com/pmndrs/react-three-fiber/llms.txt

React Three Fiber provides a robust event system for 3D objects, supporting raycasting and event bubbling. Events carry both standard DOM event data and Three.js intersection details, allowing for interactive 3D scenes. Event handlers like onClick, onPointerOver, and onPointerMove can be attached to mesh components.

```jsx
import { useState, useRef } from 'react'

function InteractiveMesh() {
  const [hovered, setHovered] = useState(false)
  const [active, setActive] = useState(false)
  const meshRef = useRef()

  return (
    <mesh
      ref={meshRef}
      scale={active ? 1.5 : 1}
      onClick={(event) => {
        event.stopPropagation() // Prevent event from reaching objects behind
        setActive(!active)
        console.log('Hit point:', event.point)
        console.log('Distance:', event.distance)
        console.log('Face normal:', event.face.normal)
      }}
      onContextMenu={(event) => console.log('Right click')}
      onDoubleClick={(event) => console.log('Double click')}
      onPointerOver={(event) => {
        event.stopPropagation()
        setHovered(true)
        document.body.style.cursor = 'pointer'
      }}
      onPointerOut={(event) => {
        setHovered(false)
        document.body.style.cursor = 'auto'
      }}
      onPointerDown={(event) => {
        // Capture pointer for drag operations
        event.target.setPointerCapture(event.pointerId)
      }}
      onPointerUp={(event) => {
        event.target.releasePointerCapture(event.pointerId)
      }}
      onPointerMove={(event) => {
        // event.point contains the intersection point in world coordinates
        if (meshRef.current) {
          meshRef.current.position.x = event.point.x
        }
      }}
    >
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial color={hovered ? 'hotpink' : 'orange'} />
    </mesh>
  )
}

```

