### Configure CameraControls

Source: https://context7.com/pmndrs/drei/llms.txt

A robust camera control implementation providing smooth movement, zooming, and panning. It supports custom mouse/touch mappings and imperative control via refs.

```jsx
import { Canvas } from '@react-three/fiber'
import { CameraControls, CameraControlsImpl } from '@react-three/drei'
import { useRef } from 'react'

const { ACTION } = CameraControlsImpl

function Scene() {
  const controlsRef = useRef()

  const handleFocus = () => {
    controlsRef.current?.setLookAt(0, 2, 5, 0, 0, 0, true)
  }

  return (
    <Canvas>
      <CameraControls
        ref={controlsRef}
        makeDefault
        mouseButtons={{
          left: ACTION.ROTATE,
          middle: ACTION.DOLLY,
          right: ACTION.TRUCK,
          wheel: ACTION.DOLLY,
        }}
        touches={{
          one: ACTION.TOUCH_ROTATE,
          two: ACTION.TOUCH_DOLLY_TRUCK,
          three: ACTION.TOUCH_DOLLY_TRUCK,
        }}
        onControlStart={() => console.log('Control started')}
        onControlEnd={() => console.log('Control ended')}
        onUpdate={() => console.log('Camera updated')}
      />
      <mesh onClick={handleFocus}>
        <boxGeometry />
        <meshStandardMaterial />
      </mesh>
    </Canvas>
  )
}
```

